INSERT INTO question (id, question_type_id, text) VALUES
                                                      (1, 1, 'A1. Uveď své jméno a příjmení.'),
                                                      (2, 1, 'A2. Uveď e-mailovou adresu pro komunikaci v rámci projektu.'),
                                                      (3, 1, 'A3. Ve kterém městě máš trvalý pobyt?'),
                                                      (4, 1, 'A4. Jaká je tvoje herní přezdívka (nickname) ve hře Counter-Strike (CS2)?'),
                                                      (5, 4, 'A5. Jsi registrován/a v některé z následujících esportových organizací nebo platforem? (lze označit více možností)'),
                                                      (6, 3, 'A6. Jsi aktuálně členem esportového týmu nebo organizace?'),
                                                      (7, 1, 'A7. Pokud jsi členem esportového týmu nebo organizace, uveď název týmu/organizace.'),
                                                      (8, 4, 'A8. Jaká je tvoje role v týmu? (lze označit více možností)'),
                                                      (9, 3, 'A9. Kolik kompetitivních zápasů odehraješ týdně?'),
                                                      (10, 3, 'A10. Máš strukturovaný tréninkový plán?'),
                                                      (11, 3, 'A11. Máš trenéra nebo analytika výkonu?'),
                                                      (12, 3, 'A12. Jak často analyzuješ svůj výkon (např. replay, statistiky apod.)?');
INSERT INTO question (id, question_type_id, text) VALUES
                                                      (13, 3, 'B1. Jaká je tvoje hlavní sportovní/pohybová činnost?'),
                                                      (14, 3, 'B2. Jaká je tvoje primární herní platforma?'),
                                                      (15, 3, 'B3. Jaký je tvůj hlavní herní žánr?'),
