                                                      (26, 3, 'B14. Jak často končíš herní session méně než 2 hodiny před spaním?');
INSERT INTO question (id, question_type_id, text) VALUES
                                                      (27, 3, 'C1. Jak náročná je pro tebe kognitivní zátěž (koncentrace, multitasking) během herní session?'),
                                                      (28, 3, 'C2. Jak vysokou emoční zátěž (prožívání hry) během herní session vnímáš?'),
                                                      (29, 3, 'C3. Jak často během herních session zažíváš tzv. "tilt" (ztrátu kontroly nad emocemi)?'),
                                                      (30, 3, 'C4. Jak vysokou vizuální zátěž při herní session subjektivně vnímáš?'),
                                                      (31, 4, 'C5. Míváš při hře některé z následujících vizuálních obtíží? (lze označit více možností)'),
                                                      (32, 4, 'C6. Kdy se tyto obtíže nejčastěji objevují? (lze označit více možností)'),
                                                      (33, 3, 'C7. Jaké formy ochrany proti modrému světlu využíváš?'),
                                                      (34, 3, 'C8. Jak často během herní session děláš "oční pauzy" (odklon pohledu od monitoru)?'),
                                                      (35, 3, 'C9. Jak často měníš vědomě během herní session držení těla?'),
                                                      (36, 4, 'C10. Užíváš pro podporu výkonu při hraní některé z následujících látek nebo doplňků? (lze označit více možností)'),
                                                      (37, 3, 'C11. Uvědomuji si dlouhodobou zátěž spojenou s esportem.'),
                                                      (38, 3, 'C12. Jsem ochoten/ochotna měnit své herní návyky směrem ke zdravějšímu režimu.'),
                                                      (39, 3, 'C13. Mám zájem o preventivní nebo odborné vedení v oblasti esportu.'),
                                                      (40, 3, 'C14. Jak často během herní session pociťuješ mentální (kognitivní) únavu?'),
                                                      (41, 3, 'C15. Jak často během herní session pociťuješ, že únava negativně ovlivňuje tvůj výkon?'),
                                                      (42, 3, 'C16. Jak často během herní session pociťuješ, že stres negativně ovlivňuje tvůj výkon?'),
                                                      (43, 3, 'C17. Jak často během herní session pociťuješ, že vizuální zátěž negativně ovlivňuje tvůj výkon?');
INSERT INTO question (id, question_type_id, text) VALUES
                                                      (44, 3, 'D1. Kolik dní v týdnu vykonáváš alespoň 30 minut souvislé fyzické aktivity?'),
                                                      (45, 3, 'D2. Kolik minut denně se v průměru věnuješ fyzické aktivitě střední nebo vysoké intenzity (při které se zadýcháš)?'),
