                                                      (51, 1, 'D8. Jaké kompenzační mechanismy používáš pro regeneraci?');
INSERT INTO question (id, question_type_id, text) VALUES
                                                      (52, 3, 'E1. Jaký typ herní myši používáš?'),
                                                      (53, 3, 'E2. Jaký způsob držení myši používáš nejčastěji? (grip style)'),
                                                      (54, 3, 'E3. Jak často během herní session měníš způsob držení myši?'),
                                                      (55, 3, 'E4. Jakou intenzitou obvykle svíráš myš během herní session?'),
                                                      (56, 3, 'E5. Jak často během herní session využíváš převážně pohyb prstů (jemné mikropohyby)?'),
                                                      (57, 3, 'E6. Jak často během herní session využíváš převážně pohyb zápěstí?'),
                                                      (58, 3, 'E7. Který typ pohybu během herní session využíváš nejvíce?'),
                                                      (59, 3, 'E8. Jak často během herní session využíváš pohyb celého předloktí?'),
                                                      (60, 3, 'E9. Jak dobře odpovídá velikost tvé herní myši velikosti tvé ruky?'),
                                                      (61, 3, 'E10. Jak vhodný je tvar tvé myši pro způsob, jakým ji držíš?'),
                                                      (62, 3, 'E11. Jak ergonomická je podle tebe tvoje herní myš při dlouhodobém hraní?'),
                                                      (63, 3, 'E12. Jak často během herní session měníš polohu ruky na myši kvůli pohodlí?'),
                                                      (64, 3, 'E13. Jak vhodná je hmotnost tvé myši pro tvůj herní styl?'),
