                                                      (66, 3, 'E15. Způsob, jakým držím myš, mi během herní session umožňuje rychlé reakce.'),
                                                      (67, 3, 'E16. Během delší herní session se mi zhoršuje kontrola a přesnost pohybu myši.'),
                                                      (68, 3, 'E17. Při únavě ruky se mi během herní session snižuje kontrola a přesnost pohybu myši.'),
                                                      (69, 3, 'E18. Velikost a tvar mé herní myši pozitivně ovlivňují můj herní výkon.');
INSERT INTO question (id, question_type_id, text) VALUES
